"use client";

import { motion } from "framer-motion";
import { cn } from "@/lib/utils";

interface SectionProps {
  id: string;
  title: string;
  tag?: string;
  children: React.ReactNode;
  className?: string;
  asymmetric?: boolean;
}

export default function Section({
  id,
  title,
  tag,
  children,
  className,
  asymmetric = false,
}: SectionProps) {
  return (
    <section id={id} className={cn("py-32 border-t border-border px-4", className)}>
      <div className="container mx-auto">
        <div className={cn("grid gap-12", asymmetric ? "grid-cols-1 lg:grid-cols-12" : "grid-cols-1")}>
          <div className={cn(asymmetric ? "lg:col-span-4" : "mb-12")}>
            {tag && (
              <span className="font-mono text-[10px] uppercase tracking-[0.3em] text-accent mb-4 block">
                {tag}
              </span>
            )}
            <h2 className="text-4xl md:text-6xl font-bold uppercase leading-none">
              {title}
            </h2>
          </div>
          <div className={cn(asymmetric ? "lg:col-span-8 lg:pt-16" : "")}>
            {children}
          </div>
        </div>
      </div>
    </section>
  );
}
