"use client";

import Link from "next/link";
import { motion } from "framer-motion";
import { ArrowUpRight } from "lucide-react";
import { cn } from "@/lib/utils";

interface ArrowLinkProps {
  href: string;
  label: string;
  className?: string;
  size?: "default" | "large";
}

export default function ArrowLink({
  href,
  label,
  className,
  size = "default",
}: ArrowLinkProps) {
  return (
    <Link href={href} className={cn("group block w-full", className)}>
      <motion.div
        className={cn(
          "flex items-center justify-between border-b border-border py-4 transition-colors group-hover:bg-accent/5",
          size === "large" ? "py-8" : "py-4"
        )}
      >
        <span
          className={cn(
            "font-display uppercase tracking-tight transition-all group-hover:pl-4",
            size === "large" ? "text-4xl md:text-7xl" : "text-xl md:text-2xl"
          )}
        >
          {label}
        </span>
        <div className="relative overflow-hidden pr-4">
          <motion.div
            initial={{ x: -20, y: 20, opacity: 0 }}
            whileHover={{ x: 0, y: 0, opacity: 1 }}
            transition={{ type: "spring", stiffness: 300, damping: 20 }}
          >
            <ArrowUpRight
              className={cn(
                "text-accent",
                size === "large" ? "h-12 w-12" : "h-6 w-6"
              )}
            />
          </motion.div>
          <motion.div
            animate={{ x: 0, y: 0, opacity: 1 }}
            whileHover={{ x: 20, y: -20, opacity: 0 }}
            className="absolute inset-0"
            transition={{ type: "spring", stiffness: 300, damping: 20 }}
          >
            <ArrowUpRight
              className={cn(
                "text-foreground/50",
                size === "large" ? "h-12 w-12" : "h-6 w-6"
              )}
            />
          </motion.div>
        </div>
      </motion.div>
    </Link>
  );
}
